import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import socket from '../socket/socket';
import axios from 'axios';

const AdminDashboard = () => {
  const { token } = useAuth();
  const [bids, setBids] = useState([]);
  const [teams, setTeams] = useState([]);
  const [winner, setWinner] = useState(null);
  const [roundActive, setRoundActive] = useState(false);

  useEffect(() => {
    socket.emit('join-admin');

    socket.on('new-bid', (bid) => {
      setBids(prev => [...prev, bid]);
    });

    socket.on('round-ended', ({ winner }) => {
      setRoundActive(false);
      setWinner(winner);
    });

    socket.on('round-started', () => {
      setRoundActive(true);
      setBids([]);
      setWinner(null);
    });

    fetchTeams();
    fetchCurrentBids();

    return () => {
      socket.off('new-bid');
      socket.off('round-ended');
      socket.off('round-started');
    };
  }, []);

  const fetchTeams = async () => {
    const res = await axios.get('/api/admin/teams', { headers: { 'x-auth-token': token } });
    setTeams(res.data);
  };

  const fetchCurrentBids = async () => {
    const res = await axios.get('/api/admin/bids', { headers: { 'x-auth-token': token } });
    setBids(res.data);
  };

  const startRound = async () => {
    await axios.post('/api/admin/start-round', {}, { headers: { 'x-auth-token': token } });
  };

  const endRound = async () => {
    await axios.post('/api/admin/end-round', {}, { headers: { 'x-auth-token': token } });
  };

  const markResult = async (teamId, correct, bidAmount) => {
    await axios.post('/api/admin/mark-result', { teamId, correct, bidAmount }, { headers: { 'x-auth-token': token } });
    fetchTeams();
  };

  const resetCoins = async () => {
    await axios.post('/api/admin/reset-coins', {}, { headers: { 'x-auth-token': token } });
    fetchTeams();
  };

  return (
    <div className="admin-dashboard">
      <h1>Admin Panel</h1>
      <div className="controls">
        <button onClick={startRound} disabled={roundActive}>Start Round</button>
        <button onClick={endRound} disabled={!roundActive}>End Round</button>
        <button onClick={resetCoins}>Reset All Coins</button>
      </div>

      <h2>Live Bids {roundActive && '(Active)'}</h2>
      <table>
        <thead>
          <tr><th>Team</th><th>Amount</th><th>Time</th></tr>
        </thead>
        <tbody>
          {bids.map((bid, idx) => (
            <tr key={idx} className={winner && bid.team === winner.team ? 'winner' : ''}>
              <td>{bid.team?.teamName}</td>
              <td>{bid.amount}</td>
              <td>{new Date(bid.timestamp).toLocaleTimeString()}</td>
            </tr>
          ))}
        </tbody>
      </table>

      {winner && (
        <div className="winner-box">
          <h3>Winner: {winner.team} (Bid: {winner.amount})</h3>
        </div>
      )}

      <h2>Teams & Balances</h2>
      <table>
        <thead>
          <tr><th>Team</th><th>Rep</th><th>Coins</th><th>Action</th></tr>
        </thead>
        <tbody>
          {teams.map(team => (
            <tr key={team._id}>
              <td>{team.teamName}</td>
              <td>{team.repName}</td>
              <td>{team.coins}</td>
              <td>
                {winner && winner.team === team.teamName && (
                  <>
                    <button onClick={() => markResult(team._id, true, winner.amount)}>✅ Correct</button>
                    <button onClick={() => markResult(team._id, false, winner.amount)}>❌ Wrong</button>
                  </>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default AdminDashboard;
